   823→// cleanupPanels cleans up panels and ensures panels property always exists
   824→func cleanupPanels(dashboard map[string]interface{}) {
   825→	if panels, ok := dashboard["panels"].([]interface{}); ok {
   826→		// Filter out repeated panels (matches frontend getPanelSaveModels behavior)
   827→		// Frontend filters: !(panel.repeatPanelId || panel.repeatedByRow)
   828→		filteredPanels := []interface{}{}
   829→		for _, panelInterface := range panels {
   830→			if panel, ok := panelInterface.(map[string]interface{}); ok {
   831→				// Skip panels with repeatPanelId or repeatedByRow
   832→				if _, hasRepeatPanelId := panel["repeatPanelId"]; hasRepeatPanelId {
   833→					continue
   834→				}
   835→				if _, hasRepeatedByRow := panel["repeatedByRow"]; hasRepeatedByRow {
   836→					continue
   837→				}
   838→				filteredPanels = append(filteredPanels, panel)
   839→			}
   840→		}
   841→
   842→		cleanupPanelList(filteredPanels)
   843→		sortPanelsByGridPosition(filteredPanels)
   844→		dashboard["panels"] = filteredPanels
   845→	} else {
   846→		// Ensure panels property exists even if empty (matches frontend behavior)
   847→		dashboard["panels"] = []interface{}{}
   848→	}
