   869→// sortPanelsByGridPosition sorts panels by grid position (matches frontend sortPanelsByGridPos behavior)
   870→func sortPanelsByGridPosition(panels []interface{}) {
   871→	sort.SliceStable(panels, func(i, j int) bool {
   872→		panelA, okA := panels[i].(map[string]interface{})
   873→		panelB, okB := panels[j].(map[string]interface{})
   874→		if !okA || !okB {
   875→			return false
   876→		}
   877→
   878→		// Get gridPos or use default values if missing
   879→		gridPosA, okA := panelA["gridPos"].(map[string]interface{})
   880→		gridPosB, okB := panelB["gridPos"].(map[string]interface{})
   881→
   882→		// Default gridPos values (matches frontend PanelModel defaults)
   883→		defaultY := float64(0)
   884→		defaultX := float64(0)
   885→
   886→		yA := defaultY
   887→		if okA {
   888→			if y, ok := gridPosA["y"].(float64); ok {
   889→				yA = y
   890→			} else if y, ok := gridPosA["y"].(int); ok {
   891→				yA = float64(y)
   892→			}
   893→		}
   894→
   895→		yB := defaultY
   896→		if okB {
   897→			if y, ok := gridPosB["y"].(float64); ok {
   898→				yB = y
   899→			} else if y, ok := gridPosB["y"].(int); ok {
   900→				yB = float64(y)
   901→			}
   902→		}
   903→
   904→		if yA == yB {
   905→			xA := defaultX
   906→			if okA {
   907→				if x, ok := gridPosA["x"].(float64); ok {
   908→					xA = x
   909→				} else if x, ok := gridPosA["x"].(int); ok {
   910→					xA = float64(x)
   911→				}
   912→			}
   913→
   914→			xB := defaultX
   915→			if okB {
   916→				if x, ok := gridPosB["x"].(float64); ok {
   917→					xB = x
   918→				} else if x, ok := gridPosB["x"].(int); ok {
   919→					xB = float64(x)
   920→				}
   921→			}
   922→			return xA < xB
   923→		}
   924→		return yA < yB
   925→	})
   926→}
