   939→// applyPanelAutoMigration applies the same auto-migration logic as the frontend PanelModel constructor
   940→func applyPanelAutoMigration(panel map[string]interface{}) {
   941→	panelType, ok := panel["type"].(string)
   942→	if !ok {
   943→		return
   944→	}
   945→
   946→	var newType string
   947→
   948→	// Graph needs special logic as it can be migrated to multiple panels
   949→	// Including graphite which was previously migrated to graph in the schema version 2 migration in DashboardMigrator.ts
   950→	// but this was a bug because in there graphite was set to graph, but since those migrations run
   951→	// after PanelModel.restoreModel where autoMigrateFrom is set, this caused the graph migration to be skipped.
   952→	// And this resulted in a dashboard with invalid panels.
   953→	if panelType == "graph" || panelType == "graphite" {
   954→		// Check xaxis mode for special cases
   955→		newType = getGraphAutoMigration(panel)
   956→	} else {
   957→		// Check autoMigrateAngular mapping
   958→		autoMigrateAngular := map[string]string{
   959→			"table-old":                "table",
   960→			"singlestat":               "stat",
   961→			"grafana-singlestat-panel": "stat",
   962→			"grafana-piechart-panel":   "piechart",
   963→			"grafana-worldmap-panel":   "geomap",
   964→			"natel-discrete-panel":     "state-timeline",
   965→		}
   966→
   967→		if mappedType, exists := autoMigrateAngular[panelType]; exists {
   968→			newType = mappedType
   969→		}
   970→	}
   971→
   972→	// Apply auto-migration if a new type was determined
   973→	if newType != "" {
   974→		panel["autoMigrateFrom"] = panelType
   975→		panel["type"] = newType
   976→	}
   977→}
   978→
   979→func getGraphAutoMigration(panel map[string]interface{}) string {
   980→	newType := ""
   981→	if xaxis, ok := panel["xaxis"].(map[string]interface{}); ok {
   982→		if mode, ok := xaxis["mode"].(string); ok {
   983→			switch mode {
   984→			case "series":
   985→				// Check legend values for bargauge
   986→				if legend, ok := panel["legend"].(map[string]interface{}); ok {
   987→					if values, ok := legend["values"].(bool); ok && values {
   988→						newType = "bargauge"
   989→					} else {
   990→						newType = "barchart"
   991→					}
   992→				} else {
   993→					newType = "barchart"
   994→				}
   995→			case "histogram":
   996→				newType = "histogram"
   997→			}
   998→		}
   999→	}
  1000→
  1001→	// Default graph migration to timeseries
  1002→	if newType == "" {
  1003→		newType = "timeseries"
  1004→	}
  1005→
  1006→	return newType
  1007→}
