   803→			}
   804→		case "constant":
   805→			// Constant variables: remove options completely
   806→			delete(variable, "options")
   807→		case "datasource":
   808→			// Datasource variables: always set options to empty array
   809→			variable["options"] = []interface{}{}
   810→		case "custom":
   811→			// Custom variables: no special handling (just return rest)
   812→			// This is the default behavior - no additional processing needed
   813→		case "textbox":
   814→			// Textbox variables: handle query vs originalQuery logic
   815→			// For now, just return rest (no special handling needed for basic cases)
   816→		case "adhoc":
   817→			// Adhoc variables: no special handling
   818→			// This is the default behavior - no additional processing needed
   819→		}
   820→	}
   821→}
