  1015→// removeNullValuesRecursivelyWithContext removes null values from nested objects and arrays
  1016→// This matches the frontend's JSON.stringify/parse behavior in getSaveModelClone()
  1017→func removeNullValuesRecursivelyWithContext(data interface{}, panelType string) {
  1018→	switch v := data.(type) {
  1019→	case map[string]interface{}:
  1020→		// Remove null values from map
  1021→		for key, value := range v {
  1022→			if value == nil {
  1023→				// Frontend removes null values via JSON serialization, so we should too
  1024→				// No special case needed for threshold steps
  1025→				delete(v, key)
  1026→			} else {
  1027→				// Recursively process nested values
  1028→				removeNullValuesRecursivelyWithContext(value, panelType)
  1029→			}
  1030→		}
  1031→	case []interface{}:
  1032→		// Process array elements
  1033→		for _, item := range v {
  1034→			if item != nil {
  1035→				removeNullValuesRecursivelyWithContext(item, panelType)
  1036→			}
  1037→		}
  1038→	}
  1039→}
