  1009→// removeNullValuesRecursively removes null values from nested objects and arrays
  1010→// This matches the frontend's JSON.stringify/parse behavior
  1011→func removeNullValuesRecursively(data interface{}) {
  1012→	removeNullValuesRecursivelyWithContext(data, "")
  1013→}
  1014→
  1015→// removeNullValuesRecursivelyWithContext removes null values from nested objects and arrays
  1016→// This matches the frontend's JSON.stringify/parse behavior in getSaveModelClone()
  1017→func removeNullValuesRecursivelyWithContext(data interface{}, panelType string) {
  1018→	switch v := data.(type) {
  1019→	case map[string]interface{}:
  1020→		// Remove null values from map
  1021→		for key, value := range v {
  1022→			if value == nil {
  1023→				// Frontend removes null values via JSON serialization, so we should too
  1024→				// No special case needed for threshold steps
  1025→				delete(v, key)
  1026→			} else {
  1027→				// Recursively process nested values
  1028→				removeNullValuesRecursivelyWithContext(value, panelType)
  1029→			}
  1030→		}
  1031→	case []interface{}:
  1032→		// Process array elements
  1033→		for _, item := range v {
  1034→			if item != nil {
  1035→				removeNullValuesRecursivelyWithContext(item, panelType)
  1036→			}
  1037→		}
  1038→	}
  1039→}
  1040→
  1041→// removeIfDefaultValue removes the key from the map if its value equals the defaultValue
  1042→func removeIfDefaultValue(data map[string]interface{}, key string, defaultValue interface{}) {
  1043→	if val, ok := data[key]; ok && isEqual(val, defaultValue) {
  1044→		delete(data, key)
  1045→	}
  1046→}
  1047→
  1048→// cleanupDashboardDefaults removes dashboard-level default values that frontend filters out
  1049→func cleanupDashboardDefaults(dashboard map[string]interface{}) {
  1050→	// Remove style if it's the default "dark" value
  1051→	removeIfDefaultValue(dashboard, "style", "dark")
  1052→
  1053→	// Remove hideControls if it's the default false value
  1054→	removeIfDefaultValue(dashboard, "hideControls", false)
  1055→
  1056→	// Remove dashboard id if it's null
  1057→	removeIfDefaultValue(dashboard, "id", nil)
  1058→
  1059→	// Remove version property - it's managed by the backend metadata, not the spec
  1060→	delete(dashboard, "version")
  1061→
